import requests

def graphql_query(
    url: str,
    query: str,
    variables: dict = None,
    token: str = None
) -> dict:
    headers = {"Content-Type": "application/json"}
    if token:
        headers["Authorization"] = token

    payload = {"query": query}
    if variables:
        payload["variables"] = variables

    response = requests.post(url, json=payload, headers=headers)
    assert response.status_code == 200, (
        f"Unexpected HTTP status: {response.status_code}. Body: {response.text[:300]}"
    )

    body = response.json()
    if "errors" in body:
        error_messages = [e.get("message", str(e)) for e in body["errors"]]
        raise AssertionError(
            f"GraphQL errors returned: {'; '.join(error_messages)}"
        )

    assert "data" in body, f"Response missing 'data' field: {body}"
    return body["data"]


