import pytest
import requests

RATE_LIMIT_HEADERS = {
    "X-RateLimit-Limit",
    "X-RateLimit-Remaining"
}

def assert_rate_limit_headers(response, *args, **kwargs):
    """Response hook that validates rate limit headers on 2xx responses."""
    if 200 <= response.status_code < 300:
        for header in RATE_LIMIT_HEADERS:
            assert header in response.headers, (
                f"Missing rate limit header '{header}' on "
                f"{response.request.method} {response.url}"
            )
        limit = int(response.headers["X-RateLimit-Limit"])
        remaining = int(response.headers["X-RateLimit-Remaining"])
        assert remaining >= 0, (
            f"X-RateLimit-Remaining is negative: {remaining}"
        )
        assert remaining <= limit, (
            f"X-RateLimit-Remaining ({remaining}) > X-RateLimit-Limit ({limit})"
        )


@pytest.fixture
def rate_limit_session():
    session = requests.Session()
    session.hooks["response"].append(assert_rate_limit_headers)
    yield session
    session.close()


# Example test
def test_list_users(rate_limit_session):
    resp = rate_limit_session.get("https://jsonplaceholder.typicode.com/users")
    assert resp.status_code == 200
    # Rate limit headers are automatically validated by the fixture hook
